        return "hold"
    def position_size(self, equity, price):
        return min((self.risk_pct * equity) / price, equity / price)
    def stop_loss(self, entry_price):
        return entry_price * (1.0 - self.mult * 0.03)
    def should_exit(self, candles, entry_price):
